import json
from datetime import datetime
from typing import NamedTuple, Optional

import boto3
import pytz
import tzlocal
from pkg_resources import resource_filename

from geosat.tools.pricetracker import PriceTracker


class InstanceDescription(NamedTuple):
    instance_type: str
    uptime_seconds: float
    platform_details: str


class AWSInstanceIDNotFoundError(Exception): ...


class AWSPriceTracker(PriceTracker):
    # Get current AWS pricing for an on-demand instance
    def get_price(self, region_description: str, instance: str, platform: str) -> float:
        # Use AWS Pricing API through Boto3
        # API only has us-east-1 and ap-south-1 as valid endpoints.
        # It doesn't have any impact on your selected region for your instance.

        # Search product filter. This will reduce the amount of data returned by the
        # get_products function of the Pricing API
        filters = [
            {"Field": "tenancy", "Value": "shared", "Type": "TERM_MATCH"},
            {"Field": "operatingSystem", "Value": platform, "Type": "TERM_MATCH"},
            {"Field": "preInstalledSw", "Value": "NA", "Type": "TERM_MATCH"},
            {"Field": "instanceType", "Value": instance, "Type": "TERM_MATCH"},
            {"Field": "location", "Value": region_description, "Type": "TERM_MATCH"},
            {"Field": "capacitystatus", "Value": "Used", "Type": "TERM_MATCH"},
        ]
        client = boto3.client("pricing", region_name="us-east-1")
        data: dict = client.get_products(ServiceCode="AmazonEC2", Filters=filters)
        on_demand: dict = json.loads(data["PriceList"][0])["terms"]["OnDemand"]
        return float(
            on_demand.popitem()[1]["priceDimensions"].popitem()[1]["pricePerUnit"][
                "USD"
            ]
        )

    # Translate region name to region description. Even though the API data contains
    # regionCode field, it will not return accurate data. However using the location
    # field will, but then we need to translate the region name into a region description.
    # You could skip this by using the region descriptions in your code directly, but most
    # other APIs are using the region name.
    def get_region_description(self, region_name: str) -> str:
        default_region = "US East (N. Virginia)"
        endpoint_file = resource_filename("botocore", "data/endpoints.json")
        try:
            with open(endpoint_file, "r", encoding="utf-8") as f:
                data = json.load(f)
        except IOError:
            return default_region
        # Botocore is using Europe while Pricing API using EU...sigh...
        return data["partitions"][0]["regions"][region_name]["description"].replace(
            "Europe", "EU"
        )

    def describe_instance(
        self, instance_id: str, region_name: str = "eu-west-3"
    ) -> InstanceDescription:
        client = boto3.client("ec2", region_name=region_name)
        response: dict = client.describe_instances(
            InstanceIds=[
                instance_id,
            ],
        )
        instance_type: str = response["Reservations"][0]["Instances"][0]["InstanceType"]
        launch_date: datetime = response["Reservations"][0]["Instances"][0][
            "LaunchTime"
        ]
        platform_details: str = response["Reservations"][0]["Instances"][0][
            "PlatformDetails"
        ]
        # we need to add info on the localzone using tzlocal in order to convert to utc
        launch_date = launch_date.replace(tzinfo=tzlocal.get_localzone())
        now_date: datetime = datetime.now(pytz.utc)  # now_date is in utc time
        uptime_seconds = (
            now_date - launch_date.astimezone(pytz.utc)
        ).total_seconds()  # launch_date is converted in utc time
        return InstanceDescription(
            instance_type=instance_type,
            uptime_seconds=uptime_seconds,
            platform_details=platform_details,
        )

    def get_instance_id(self, file: str = "/var/lib/cloud/data/instance-id") -> str:
        """Return the ec2 instance id"""
        try:
            with open(file, "r", encoding="utf-8") as f:
                instance_id: str = f.readline().split()[0]
        except FileNotFoundError as exception:
            raise AWSInstanceIDNotFoundError(
                f"{file} doesn't exist, you must be on an EC2 instance."
            ) from exception
        return instance_id

    def get_job_cost(
        self, instance_id: Optional[str] = None, region_name: str = "eu-west-3"
    ) -> float:
        if instance_id is None:
            instance_id = self.get_instance_id()
        instance_description = self.describe_instance(instance_id, region_name)
        # Get current price for a given instance, region and os
        # TODO: find a way to convert instance_description.platform_details to a suitable str for `get_price`
        price = self.get_price(
            self.get_region_description(region_name),
            instance_description.instance_type,
            "Linux",
        )
        cost: float = instance_description.uptime_seconds / 3600 * price
        return cost
